function makeSeed(question, options, correct) {
    return { question, options, correct };
}

function buildQuestionBank(subjectId, label, seeds) {
    return seeds.map((seed, index) => ({
        question: seed.question,
        options: [...seed.options],
        correct: seed.correct,
        conceptKey: `${subjectId}-${index}`,
        variantKey: `${subjectId}-${index}-0`
    }));
}

